INSERT INTO citas (id, id_paciente, id_medico, fecha_hora, duracion_minutos, motivo_preliminar, estado, confirmada, created_at) VALUES
INSERT INTO consultas (id, id_cita, id_paciente, id_medico, fecha_consulta, motivo_consulta, notas_soap, diagnostico_texto, plan_tratamiento, diagnostico_principal, firmado, created_at) VALUES
('00000000-0000-0004-0000-000000000001','00000000-0000-0003-0000-000000000001','00000000-0000-0002-0002-000000000001','00000000-0000-0002-0001-000000000003',now() - interval '15 days','Control de presión arterial','{"subjetivo":"Paciente refiere cefalea ocasional y fatiga","objetivo":"TA 165/95 mmHg, FC 82 bpm, sin soplos cardíacos","analisis":"Hipertensión no controlada, requiere optimización farmacológica","plan":"Aumentar dosis de Lisinopril a 20mg"}','Hipertensión esencial no controlada','Incrementar Lisinopril, control en 2 semanas, dieta baja en sodio','00000000-0000-0005-0000-000000000001',true,now()),
('00000000-0000-0004-0000-000000000002','00000000-0000-0003-0000-000000000003','00000000-0000-0002-0002-000000000002','00000000-0000-0002-0001-000000000004',now() - interval '7 days','Control prenatal semana 31','{"subjetivo":"Paciente sin molestias, movimientos fetales normales","objetivo":"Peso materno 78kg, TA 120/80, ganancia de 10kg, FCF 150 bpm","analisis":"Embarazo sin complicaciones, presentación cefálica","plan":"Continuar suplementación prenatal, parto esperado 2026-06-20"}','Embarazo a término sin complicaciones','Suplementación con hierro y ácido fólico, control mensual, preparación parto','00000000-0000-0005-0000-00000000000f',true,now()),
('00000000-0000-0004-0000-000000000003','00000000-0000-0003-0000-000000000005','00000000-0000-0002-0002-000000000003','00000000-0000-0002-0001-00000000000a',now() - interval '20 days','Control diabetes tipo 2','{"subjetivo":"Paciente refiere poliuria y polidipsia","objetivo":"Glucosa capilar 280 mg/dL, HbA1c 9.2%, peso 92kg","analisis":"Diabetes tipo 2 descompensada, mala adherencia al tratamiento","plan":"Ajustar dosis de metformina a 2gr/día, considerar agregar Gliptina"}','Diabetes mellitus tipo 2 descompensada','Metformina 2g/día, revisión en 4 semanas, glucometría capilar diaria','00000000-0000-0005-0000-000000000002',true,now()),
('00000000-0000-0004-0000-000000000004','00000000-0000-0003-0000-000000000007','00000000-0000-0002-0002-000000000004','00000000-0000-0002-0001-000000000006',now() - interval '10 days','Evaluación migraña','{"subjetivo":"Paciente con 3 episodios mensuales de migraña frontal con aura","objetivo":"Exploración neurológica normal, reflejo fotomotor íntegro","analisis":"Migraña con aura, posible relación con stress","plan":"Iniciar profilaxis con Propranolol 40mg/día"}','Migraña con aura','Propranolol 40mg/día, técnicas de relajación, evitar factores gatillo','00000000-0000-0005-0000-00000000000b',true,now()),
('00000000-0000-0004-0000-000000000005','00000000-0000-0003-0000-000000000009','00000000-0000-0002-0002-000000000005','00000000-0000-0002-0001-000000000007',now() - interval '5 days','Evaluación dorsal bajo','{"subjetivo":"Paciente con lumbago desde hace 1 mes post-esfuerzo","objetivo":"Dolor a la palpación paravertebral L5, limitación de flexión","analisis":"Lumbago mecánico con espasmo muscular","plan":"Prednisona 5 días, fisioterapia, ibuprofeno 600mg c/8hrs"}','Lumbago no especificado','Ibuprofeno 600mg c/8hrs, 5 días de reposo relativo, fisioterapia','00000000-0000-0005-0000-000000000006',true,now()),
('00000000-0000-0004-0000-000000000006','00000000-0000-0003-0000-00000000000b','00000000-0000-0002-0002-000000000006','00000000-0000-0002-0001-000000000005',now() - interval '12 days','Evaluación dermatitis facial','{"subjetivo":"Paciente con prurito intenso en cara y cuello por 2 semanas","objetivo":"Eritema difuso, liqueninización leve, sin vesículas","analisis":"Dermatitis de contacto alérgica, posible alergia a cosmético","plan":"Identificar alérgeno, topiramate 0.05% en zona afectada"}','Dermatitis alérgica de contacto','Crema hidratante hipoalergénica, evitar cosméticos irritantes','00000000-0000-0005-0000-000000000007',true,now()),
('00000000-0000-0004-0000-000000000007','00000000-0000-0003-0000-00000000000c','00000000-0000-0002-0002-000000000007','00000000-0000-0002-0001-000000000009',now() - interval '8 days','Evaluación gastritis','{"subjetivo":"Dolor epigástrico posprandial, acidez, reflujo","objetivo":"Exploración abdominal: dolor a la palpación epigástrica sin defensa","analisis":"Gastritis crónica erosiva, probablemente asociada a H. pylori","plan":"Test H. pylori, omeprazol 20mg/día, dieta blanda"}','Gastritis crónica erosiva','Omeprazol 20mg/día, test H. pylori, evitar irritantes gástricos','00000000-0000-0005-0000-000000000004',true,now()),
('00000000-0000-0004-0000-000000000008','00000000-0000-0003-0000-00000000000e','00000000-0000-0002-0002-000000000008','00000000-0000-0002-0001-00000000000b',now() - interval '6 days','Evaluación ansiedad','{"subjetivo":"Paciente con crisis de ansiedad 2-3 veces por semana, insomnio","objetivo":"TA 130/85, FC 92 bpm, ansiedad evidente en entrevista","analisis":"Trastorno de ansiedad generalizada, sin antecedentes psicóticos","plan":"Sertralina 50mg/día, psicoterapia cognitivo-conductual"}','Trastorno de ansiedad generalizada','Sertralina 50mg/día, psicoterapia semanal, técnicas de relajación','00000000-0000-0005-0000-000000000011',true,now()),
('00000000-0000-0004-0000-000000000009','00000000-0000-0003-0000-000000000010','00000000-0000-0002-0002-000000000009','00000000-0000-0002-0001-000000000001',now() - interval '3 days','Evaluación infección urinaria','{"subjetivo":"Disuria, polaquiuria, dolor suprapúbico","objetivo":"Exploración urológica: dolor suprapúbico, orina turbia","analisis":"Infección aguda de vías urinarias, cultivo pendiente","plan":"Ciprofloxacino 500mg c/12hrs por 7 días"}','Infección de vías urinarias aguda','Ciprofloxacino 500mg c/12hrs x 7 días, hidratación abundante','00000000-0000-0005-0000-000000000003',true,now()),
('00000000-0000-0004-0000-00000000000a','00000000-0000-0003-0000-000000000011','00000000-0000-0002-0002-00000000000a','00000000-0000-0002-0001-00000000000c',now() - interval '9 days','Control de asma','{"subjetivo":"Paciente sin disnea nocturna en últimas 2 semanas, mejor adherencia","objetivo":"Espirometría: FEV1 82% del predicho, variabilidad 12%","analisis":"Asma moderada controlada, buena respuesta a terapia","plan":"Continuar salbutamol + budesonida, revisar técnica de inhalación"}','Asma no especificada, controlada','Budesonida 200mcg c/12hrs, salbutamol PRN, revisión en 6 semanas','00000000-0000-0005-0000-000000000008',true,now()),
('00000000-0000-0004-0000-00000000000b','00000000-0000-0003-0000-000000000013','00000000-0000-0002-0002-00000000000b','00000000-0000-0002-0001-00000000001c',now() - interval '14 days','Control hiperlipidemia','{"subjetivo":"Paciente asintomático, buena adherencia al régimen","objetivo":"Colesterol total 280 mg/dL, triglicéridos 350 mg/dL, LDL 180","analisis":"Hiperlipidemia mixta mal controlada","plan":"Atorvastatina 40mg/día, dieta hipolipemiante estricta"}','Hiperlipidemia mixta','Atorvastatina 40mg/día, dieta baja en grasas saturadas','00000000-0000-0005-0000-00000000000a',true,now()),
('00000000-0000-0004-0000-00000000000c','00000000-0000-0003-0000-000000000014','00000000-0000-0002-0002-00000000000c','00000000-0000-0002-0001-000000000011',now() - interval '4 days','Evaluación rinitis alérgica','{"subjetivo":"Prurito nasal, estornudos frecuentes, rinorrea acuosa","objetivo":"Mucosa nasal edematosa y pálida, turbinatos hipertróficos","analisis":"Rinitis alérgica estacional, probable alergia a pólenes","plan":"Loratadina 10mg/día, considerar rinoplastia si persiste obstrucción"}','Rinitis alérgica debida a pólenes','Loratadina 10mg/día, sprays nasales de esteroides PRN','00000000-0000-0005-0000-00000000000e',true,now()),
('00000000-0000-0004-0000-00000000000d','00000000-0000-0003-0000-000000000015','00000000-0000-0002-0002-00000000000d','00000000-0000-0002-0001-000000000012',now() - interval '11 days','Control de gota','{"subjetivo":"Último ataque 3 semanas, dolor ha disminuido","objetivo":"Articulación 1ª MTF sin inflamación actual, movilidad completa","analisis":"Gota tofácea en remisión, requiere prevención de recaídas","plan":"Alopurinol 300mg/día, Colchicina 0.5mg/día profiláctica"}','Gota crónica','Alopurinol 300mg/día, Colchicina 0.5mg/día, evitar alcohol y purinas','00000000-0000-0005-0000-000000000010',true,now()),
('00000000-0000-0004-0000-00000000000e','00000000-0000-0003-0000-000000000016','00000000-0000-0002-0002-00000000000e','00000000-0000-0002-0001-00000000000f',now() - interval '2 days','Evaluación pre-quirúrgica colelitiasis','{"subjetivo":"Dolor intermitente en hipocondrio derecho, refiere cólicos","objetivo":"Murphy (+), exploración abdominal: defensa leve, ictericia ausente","analisis":"Colelitiasis sintomática, cálculos >1cm sin dilatación de vía biliar","plan":"Colecistectomía laparoscópica programada para 2026-05-27"}','Colelitiasis sintomática','Colecistectomía laparoscópica, ayuno preoperatorio, consentimiento informado','00000000-0000-0005-0000-000000000013',true,now()),
('00000000-0000-0004-0000-00000000000f','00000000-0000-0003-0000-000000000018','00000000-0000-0002-0002-00000000000f','00000000-0000-0002-0001-000000000008',now() - interval '16 days','Evaluación oftalmológica','{"subjetivo":"Paciente joven con miopía progresiva","objetivo":"AV OD: 20/70 corregida, OI: 20/100 corregida, refracción -3.5D ambos ojos","analisis":"Miopía moderada, requiere corrección óptica","plan":"Prescripción de lentes, considerar LASIK si lo desea"}','Miopía moderada','Lentes correctores, evaluación para LASIK en consulta posterior','00000000-0000-0005-0000-000000000012',true,now()),
('00000000-0000-0004-0000-000000000010','00000000-0000-0003-0000-000000000019','00000000-0000-0002-0002-000000000010','00000000-0000-0002-0001-000000000019',now() - interval '13 days','Evaluación reflujo gastroesofágico','{"subjetivo":"Ardor postprandial intenso, síntomas nocturnos frecuentes","objetivo":"Mucosa esofágica normal en endoscopia, sin erosiones","analisis":"ERGE moderada sin complicaciones, posible hernia hiatal","plan":"Omeprazol 20mg/día, elevar cabecera, evitar irritantes"}','Enfermedad por reflujo gastroesofágico','Omeprazol 20mg/día, cambios dietéticos y posturales','00000000-0000-0005-0000-00000000000c',true,now()),
('00000000-0000-0004-0000-000000000011','00000000-0000-0003-0000-00000000001a','00000000-0000-0002-0002-000000000011','00000000-0000-0002-0001-00000000001c',now() - interval '18 days','Control de hipotiroidismo','{"subjetivo":"Paciente con fatiga leve, sin síntomas de hipotiroidismo","objetivo":"TA 120/75, FC 68 bpm, sin bocio, reflejos normales","analisis":"Hipotiroidismo bien controlado con levotiroxina","plan":"Continuar levotiroxina 75mcg/día, TSH en 6 semanas"}','Hipotiroidismo no especificado','Levotiroxina 75mcg/día, laboratorios en 6 semanas','00000000-0000-0005-0000-000000000014',true,now()),
('00000000-0000-0004-0000-000000000012','00000000-0000-0003-0000-00000000001c','00000000-0000-0002-0002-000000000012','00000000-0000-0002-0001-00000000001d',now() - interval '1 day','Evaluación depresión','{"subjetivo":"Anhedonia, insomnio, ideación suicida pasiva","objetivo":"Paciente triste, hipomimia, lentitud psicomotora evidente","analisis":"Episodio depresivo mayor, requiere intervención urgente","plan":"Sertralina 50mg/día, psicoterapia intensiva, apoyo familiar"}','Episodio depresivo mayor moderado','Sertralina 50mg/día, psicoterapia semanal, seguimiento cercano','00000000-0000-0005-0000-000000000005',true,now()),
('00000000-0000-0004-0000-000000000013','00000000-0000-0003-0000-00000000001d','00000000-0000-0002-0002-000000000013','00000000-0000-0002-0001-000000000013',now() - interval '21 days','Chequeo médico preventivo','{"subjetivo":"Paciente asintomático, desea chequeo anual de salud","objetivo":"TA 125/80, FC 72 bpm, peso 82kg, IMC 26.5, sin hallazgos patológicos","analisis":"Paciente sano, sobrepeso leve, sin factores de riesgo relevantes","plan":"Laboratorios anuales, continuar estilo de vida saludable"}','Examen médico general','Laboratorios anuales, mantener actividad física, dieta equilibrada','00000000-0000-0005-0000-00000000000d',true,now()),
('00000000-0000-0004-0000-000000000014','00000000-0000-0003-0000-00000000001f','00000000-0000-0002-0002-000000000014','00000000-0000-0002-0001-00000000000d',now() - interval '7 days','Evaluación IVU recurrente','{"subjetivo":"3ª IVU en 3 meses, disuria y polaquiuria","objetivo":"Análisis de orina: piuria 40/campo, bacteriuria (+), nitritos (+)","analisis":"Infección recurrente de vías urinarias, requiere evaluación urológica","plan":"Antibioticoterapia, estudios de imagen, considerar profilaxis"}','Infección recurrente de vías urinarias','Ciprofloxacino 500mg c/12hrs x 7 días, propuesta investigativa','00000000-0000-0005-0000-00000000000f',true,now())
