-- ================================================================
-- SECCIÓN 0: AJUSTES DE ESQUEMA
-- ================================================================
ALTER TABLE medicos ADD COLUMN IF NOT EXISTS id_usuario UUID;
ALTER TABLE medicos ADD COLUMN IF NOT EXISTS ciudad VARCHAR(100);
ALTER TABLE medicos ADD COLUMN IF NOT EXISTS descripcion TEXT;
ALTER TABLE medicos ADD COLUMN IF NOT EXISTS horarios JSONB DEFAULT '{}';
ALTER TABLE medicos ADD COLUMN IF NOT EXISTS consulta_precio DECIMAL(10,2) DEFAULT 800.00;
ALTER TABLE medicos ADD COLUMN IF NOT EXISTS foto_url TEXT;
ALTER TABLE medicos ADD COLUMN IF NOT EXISTS activo BOOLEAN DEFAULT true;
ALTER TABLE medicos ADD COLUMN IF NOT EXISTS cedula_profesional VARCHAR(20);
ALTER TABLE medicos ADD COLUMN IF NOT EXISTS telefono VARCHAR(20);
ALTER TABLE medicos ADD COLUMN IF NOT EXISTS calificacion DECIMAL(3,2) DEFAULT 4.8;
ALTER TABLE medicos ADD COLUMN IF NOT EXISTS num_resenas INT DEFAULT 0;

ALTER TABLE medicos ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS medicos_directorio_publico ON medicos;
CREATE POLICY medicos_directorio_publico ON medicos FOR SELECT TO authenticated USING (activo = true);

DROP POLICY IF EXISTS medico_update_own ON medicos;
CREATE POLICY medico_update_own ON medicos FOR ALL TO authenticated USING (id_usuario = auth.uid());

